print("SCRIPT INICIADO")--[[ Hillo Hub - Mobile (No Rayfield) Compatible con Delta Executor ]]-- local Players = game:GetService("Players") local UIS = game:GetService("UserInputService") local RunService = game:GetService("RunService") local VirtualInputManager = game:GetService("VirtualInputManager") local LocalPlayer = Players.LocalPlayer -- UI BASE local screenGui = Instance.new("ScreenGui") screenGui.Name = "HilloHubUI" screenGui.Parent = game.CoreGui local frame = Instance.new("Frame", screenGui) frame.Size = UDim2.new(0, 200, 0, 220) frame.Position = UDim2.new(0, 20, 0.3, 0) frame.BackgroundColor3 = Color3.fromRGB(25,25,25) frame.BorderSizePixel = 0 local title = Instance.new("TextLabel", frame) title.Size = UDim2.new(1,0,0,30) title.Text = "Hillo Hub" title.TextColor3 = Color3.new(1,1,1) title.BackgroundTransparency = 1 -- DRAG local dragging, dragInput, dragStart, startPos frame.InputBegan:Connect(function(input) if input.UserInputType == Enum.UserInputType.Touch then dragging = true dragStart = input.Position startPos = frame.Position end end) UIS.InputChanged:Connect(function(input) if dragging and input.UserInputType == Enum.UserInputType.Touch then local delta = input.Position - dragStart frame.Position = UDim2.new(startPos.X.Scale, startPos.X.Offset + delta.X, startPos.Y.Scale, startPos.Y.Offset + delta.Y) end end) UIS.InputEnded:Connect(function(input) if input.UserInputType == Enum.UserInputType.Touch then dragging = false end end) -- BOTÓN GENERADOR local function createButton(text, yPos, callback) local btn = Instance.new("TextButton", frame) btn.Size = UDim2.new(1, -10, 0, 30) btn.Position = UDim2.new(0, 5, 0, yPos) btn.Text = text btn.BackgroundColor3 = Color3.fromRGB(40,40,40) btn.TextColor3 = Color3.new(1,1,1) btn.MouseButton1Click:Connect(callback) return btn end -- VARIABLES local autoFish = false local infJump = false -- WALK SPEED createButton("Speed x2", 40, function() local char = LocalPlayer.Character if char then local hum = char:FindFirstChildOfClass("Humanoid") if hum then hum.WalkSpeed = 32 end end end) -- INFINITE JUMP createButton("Infinite Jump", 80, function() infJump = not infJump end) UIS.JumpRequest:Connect(function() if infJump then local hum = LocalPlayer.Character and LocalPlayer.Character:FindFirstChildOfClass("Humanoid") if hum then hum:ChangeState("Jumping") end end end) -- AUTOFISH createButton("Auto Fish", 120, function() autoFish = not autoFish end) -- CLICK GUI (FIX MOBILE) local function clickGui(gui) local pos = gui.AbsolutePosition local size = gui.AbsoluteSize local x = pos.X + size.X/2 local y = pos.Y + size.Y/2 local inset = game:GetService("GuiService"):GetGuiInset() x = x + inset.X y = y + inset.Y VirtualInputManager:SendMouseButtonEvent(x,y,0,true,game,0) VirtualInputManager:SendMouseButtonEvent(x,y,0,false,game,0) end -- AUTOFISH LOGIC local fishingUI = LocalPlayer.PlayerGui:WaitForChild("Fishing"):WaitForChild("Frame") fishingUI.ChildAdded:Connect(function(bar) if not autoFish then return end if bar.Name ~= "Template" then return end local frameBar = bar:WaitForChild("Frame") local last local conn conn = RunService.RenderStepped:Connect(function() if not autoFish then conn:Disconnect() return end if not bar.Parent then conn:Disconnect() return end local diff = frameBar.AbsoluteSize.X - bar.AbsoluteSize.X if last and last > 0 and diff <= 0 then task.wait() clickGui(bar) conn:Disconnect() end last = diff end) end) -- AUTO REEL task.spawn(function() local clicked = false while true do if autoFish then local char = LocalPlayer.Character if char then for _,tool in pairs(char:GetChildren()) do if tool:FindFirstChild("Cast") then local bob = tool.Cast:FindFirstChild("Bobber") if bob then local effect = bob:FindFirstChild("Effect") if effect and effect.Enabled and not clicked then local m = LocalPlayer:GetMouse() VirtualInputManager:SendMouseButtonEvent(m.X,m.Y,0,true,game,0) VirtualInputManager:SendMouseButtonEvent(m.X,m.Y,0,false,game,0) clicked = true end else clicked = false end end end end end task.wait(0.01) end end) print("Hillo Hub Mobile Loaded (No Rayfield)")
